Based on the reference materials and detailed specifications, here's the complete implementation for the `create_eas_database` function:

```cpp
#pragma once

#include <filesystem>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace test_create_eas_database {
  void create_eas_database() {
    // Create the data directory if it doesn't exist
    if (!std::filesystem::exists("data")) {
      std::filesystem::create_directory("data");
    }

    // Connect to the main database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");

    // Execute the ATTACH DATABASE statement
    auto attach_stmt = sqlgen::exec("ATTACH DATABASE 'data/eas_database.db' AS EAS_DB;");

    // Apply the attach statement to the connection
    attach_stmt(conn_result.value());
  }
}
```

