  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return 1; // Connection failed
  }
  auto conn = conn_result.value();

  // 2. Begin a transaction
  auto begin_result = begin_transaction(conn);
  if (!begin_result) {
    return 1; // Transaction begin failed
  }

  // 3. Delete users where last_login is before 2025-01-01
  auto delete_op = sqlgen::delete_from<User> | sqlgen::where("last_login"_c < "2025-01-01");
  auto delete_result = delete_op(conn);
  if (!delete_result) {
    return 1; // Delete operation failed
  }

  // 4. Commit the transaction
  auto commit_result = commit(conn);
  if (!commit_result) {
    return 1; // Commit failed
  }

  // 5. Return the result of the commit
  return 0; // Success
}

} // namespace delete_inactive_users
