    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // 2. Create tables using write with empty containers
    sqlgen::write(conn, std::vector<Customer>{});
    sqlgen::write(conn, std::vector<Order>{});
    sqlgen::write(conn, std::vector<OrderItem>{});
    sqlgen::write(conn, std::vector<Product>{});

    // 3. Construct the query using sqlgen's fluent interface
    auto query = sqlgen::select_from<Customer, "c">(
        "name"_p | sqlgen::as<"product_name">,
        "order_date"_o,
        "quantity"_oi
    )
    | sqlgen::inner_join<Order, "o">("customer_id"_c == "customer_id"_o)
    | sqlgen::inner_join<OrderItem, "oi">("order_id"_o == "order_id"_oi)
    | sqlgen::inner_join<Product, "p">("product_id"_oi == "product_id"_p)
    | sqlgen::where("customer_id"_c == customer_id)
    | sqlgen::order_by("order_date"_o.desc());

    // 4. Execute the query and return results
    return query(conn).value();
}

