  std::string alter_is_active = "ALTER TABLE " + table_name +
                              " ADD COLUMN is_active INTEGER DEFAULT 1;";

  // Execute the ALTER TABLE statements
  auto result1 = conn->execute(alter_phone);
  if (!result1) {
    return false;
  }

