#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }

  auto conn = conn_result.value();

  // Chain operations using the | operator
  auto result = sqlgen::begin_transaction | conn
                | (sqlgen::read<std::vector<Account>> 
                   | sqlgen::where("account_id"_c == from_account_id))
                | (sqlgen::update<Account>(
                    "balance"_c.set("balance"_c - amount),
                    "account_id"_c.set("account_id"_c)
