                | (sqlgen::update<Account>(
                    "balance"_c.set("balance"_c + amount),
                    "account_id"_c.set("account_id"_c)
                  ) | sqlgen::where("account_id"_c == to_account_id))
                | sqlgen::commit;

  // Handle transaction result
  if (result) {
    return true;
  } else {
    // Automatic rollback on failure
    return false;
  }
}

}  // namespace transaction_transfer_funds
