void update_eas_table() {
  design_eas_database_with_major();

  // 1. Add new column 'Grade' to Score table (char(1), not null)
  sqlgen::sqlite::connect(db_path)
      .and_then(sqlgen::alter_table<Score> | sqlgen::add_column<Score, char, "Grade">)
      .and_then([](auto&& conn) {
        // Execute ALTER TABLE to set NOT NULL constraint
        return sqlgen::exec(conn, "ALTER TABLE Score ALTER COLUMN Grade SET NOT NULL");
      })
      .and_then(sqlgen::create_index<"idx_score_grade", Score, char>("Grade"))
      .and_then([](auto&& conn) {
        // 2. Modify Age column in Student table to int with null allowance
        return sqlgen::exec(conn, 
            "ALTER TABLE Student "
            "ALTER COLUMN Age TYPE INTEGER USING (Age::integer), "
            "ALTER COLUMN Age DROP NOT NULL");
      })
      .and_then([](auto&& conn) {
        // 3. Drop Major table
        return sqlgen::exec(conn, "DROP TABLE IF EXISTS Major");
      })
      .value();
}

