  // Update account 1: increase balance by 500, set status to "COMPLETED"
  auto update_stmt = sqlgen::update<Account>(
    "balance"_c.set("balance"_c + 500.0),
    "status"_c.set("COMPLETED")
  ) | sqlgen::where("account_id"_c == 1);

  auto update_result = update_stmt(conn);
  if (!update_result.is_ok()) {
    return false;
  }

  // 4. Update account 2: set balance to 1000 and status to "ACTIVE"
  // Using alternative syntax with direct values
  auto update_stmt2 = sqlgen::update<Account>(
    "balance"_c.set(1000.0),
    "status"_c.set("ACTIVE")
  ) | sqlgen::where("account_id"_c == 2);

