  for (const auto& acc : accounts) {
    if (acc.account_id == 2 && acc.balance == 1000.0 && acc.status == "ACTIVE") {
      account2_updated = true;
      break;
    }
  }

  return account1_updated && account2_updated;
}

}  // namespace update_set_operations
